#nullable enable // autogenerated

using MVZ2.GameContent.Buffs.Enemies;
using MVZ2.Vanilla.Entities;
using PVZEngine.Buffs;
using PVZEngine.Callbacks;
using PVZEngine.Damages;
using PVZEngine.Entities;
using PVZEngine.Level;

namespace MVZ2.GameContent.Enemies
{
    [EntityBehaviourDefinition(VanillaEnemyNames.FlyingPot)]
    public class FlyingPot : AIEntityBehaviour
    {
        public FlyingPot(string nsp, string name) : base(nsp, name)
        {
        }

        public override void Init(Entity entity)
        {
            base.Init(entity);
            var fly = entity.AddBuff<FlyBuff>();
            fly.SetProperty(FlyBuff.PROP_TARGET_HEIGHT, 30f);
        }

        public override void PreTakeDamage(DamageInput damageInfo, CallbackResult result)
        {
            base.PreTakeDamage(damageInfo, result);
            if (damageInfo.Amount != 1f)
            {
                damageInfo.SetAmount(1f);
            }
        }

    }
}
